export class ConditionRegistry implements c.Contract {
  // CodeCell will be populated after compilation
  static CodeCell: c.Cell = c.Cell.EMPTY;

  readonly address: c.Address;
  readonly init: { code: c.Cell; data: c.Cell } | undefined;

  constructor(address: c.Address, init?: { code: c.Cell; data: c.Cell }) {
    this.address = address;
    this.init = init;
  }

  static fromAddress(address: c.Address): ConditionRegistry {
    return new ConditionRegistry(address);
  }

  static fromStorage(
    storage: RegistryStorage,
    code?: c.Cell,
  ): ConditionRegistry {
    const data = registryStorageToCell(storage);
    const contractCode = code ?? ConditionRegistry.CodeCell;
    const stateInit = { code: contractCode, data };
    const address = c.contractAddress(0, stateInit);
    return new ConditionRegistry(address, stateInit);
  }

  async sendDeploy(
    provider: ContractProvider,
    via: Sender,
    value: bigint,
  ): Promise<void> {
    await provider.internal(via, {
      value,
      body: c.Cell.EMPTY,
    });
  }

  async sendPrepareCondition(
    provider: ContractProvider,
    via: Sender,
    value: bigint,
    params: {
      oracle: c.Address;
      questionId: bigint;
      outcomeSlotCount: number;
    },
  ): Promise<void> {
    await provider.internal(via, {
      value,
      body: buildPrepareCondition(params),
    });
  }

  async sendReportPayouts(
    provider: ContractProvider,
    via: Sender,
    value: bigint,
    params: {
      questionId: bigint;
      payouts: bigint[];
    },
  ): Promise<void> {
    await provider.internal(via, {
      value,
      body: buildReportPayouts(params),
    });
  }

  async sendMergePositions(
    provider: ContractProvider,
    via: Sender,
    value: bigint,
    params: {
      collateralToken: c.Address;
      parentCollectionId: bigint;
      conditionId: bigint;
      partition: bigint[];
      amount: bigint;
    },
  ): Promise<void> {
    await provider.internal(via, {
      value,
      body: buildMergePositions(params),
    });
  }

  async sendRedeemPositions(
    provider: ContractProvider,
    via: Sender,
    value: bigint,
    params: {
      collateralToken: c.Address;
      parentCollectionId: bigint;
      conditionId: bigint;
      indexSets: bigint[];
    },
  ): Promise<void> {
    await provider.internal(via, {
      value,
      body: buildRedeemPositions(params),
    });
  }

  async getOwner(provider: ContractProvider): Promise<c.Address> {
    const result = await provider.get('owner', []);
    return result.stack.readAddress();
  }

  async getCondition(
    provider: ContractProvider,
    conditionId: bigint,
  ): Promise<{
    oracle: c.Address;
    questionId: bigint;
    outcomeSlotCount: number;
    payoutDenominator: bigint;
  }> {
    const result = await provider.get('get_condition', [
      { type: 'int', value: conditionId },
    ]);
    const oracle = result.stack.readAddress();
    const questionId = result.stack.readBigNumber();
    const outcomeSlotCount = Number(result.stack.readBigNumber());
    const payoutDenominator = result.stack.readBigNumber();
    return { oracle, questionId, outcomeSlotCount, payoutDenominator };
  }
}
